  const getSafeOrbitRadius = (id: string) => {
     const p = PLANETS.find(x => x.id === id);
     if (!p) return 12; // Fallback

     // Calculate closer orbit
     // If it has rings, we need to stay outside them (roughly size * 2.5)
     // If it's a rocky planet, we can get much closer (size * 1.5 + padding)
     if (p.hasRings) {
         return p.size * 2.5 + 2.0; 
     }
     return p.size * 1.8 + 2.0; 
  };

  useFrame((state, delta) => {
    if (!groupRef.current) return;

