export const Starship: React.FC<StarshipProps> = ({ planetRefs }) => {
  const groupRef = useRef<Group>(null);
  const shipModelRef = useRef<Group>(null);

  // Logic State
  const [targetId, setTargetId] = useState<string | null>(null);
  const [currentSpeedDisplay, setCurrentSpeedDisplay] = useState(0);

  const stateRef = useRef<ShipState>('SEARCHING');
  const initializedRef = useRef(false);

  // Movement calculation refs
  const currentSpeedRef = useRef(0);
  const orbitAngleRef = useRef(0);
  const orbitRadiusRef = useRef(15);
  const totalOrbitTraveledRef = useRef(0);
  const camDistRef = useRef(16); 

  // Leaving/Vector Refs
  const exitVectorRef = useRef(new Vector3());
  const leavingTimeRef = useRef(0);
  const flightVectorRef = useRef(new Vector3(0, 0, 1)); // Direction of flight

  // Constants
  const MAX_SPEED = 25; 
  const ORBIT_SPEED = 8; 

  const getSafeOrbitRadius = (id: string) => {
     const p = PLANETS.find(x => x.id === id);
     if (!p) return 12;
     return p.hasRings ? p.size * 2.5 + 2.0 : p.size * 1.8 + 2.0; 
  };

  useFrame((state, delta) => {
    if (!groupRef.current) return;

    // --- 0. INITIALIZATION ---
    if (!initializedRef.current) {
      const earthObj = planetRefs.current['earth'];
      if (earthObj) {
        const startPos = new Vector3();
        earthObj.getWorldPosition(startPos);
        if (startPos.lengthSq() > 1) {
             startPos.y += 10.0;
             startPos.x += 10.0; 
             groupRef.current.position.copy(startPos);
             groupRef.current.lookAt(new Vector3(0, 0, 0)); 
             initializedRef.current = true;

             // Initial Flight Vector
             groupRef.current.getWorldDirection(flightVectorRef.current);

             const initCamPos = startPos.clone().add(new Vector3(0, 10, 25));
             state.camera.position.copy(initCamPos);
             state.camera.lookAt(startPos);
        }
      }
      return; 
    }

    // --- 1. TARGET MANAGEMENT ---
    if (stateRef.current === 'SEARCHING') {
      const ids = Object.keys(planetRefs.current);
      if (ids.length > 0) {
        const currentPos = groupRef.current.position;
        // Don't pick nearby planets
        const validIds = ids.filter(id => {
           const pObj = planetRefs.current[id];
           const pPos = new Vector3();
           pObj.getWorldPosition(pPos);
           return pPos.distanceTo(currentPos) > 60; 
        });

        const nextId = validIds.length > 0 
           ? validIds[Math.floor(Math.random() * validIds.length)]
           : ids[Math.floor(Math.random() * ids.length)];

        setTargetId(nextId);
        stateRef.current = 'TRAVELING';
      }
      return;
    }

    let targetObj: Object3D | null = null;
    let targetPos = new Vector3();
    if (targetId && planetRefs.current[targetId]) {
      targetObj = planetRefs.current[targetId];
      targetObj.getWorldPosition(targetPos);
    }

    const currentPos = groupRef.current.position.clone();

    // --- 2. STATE LOGIC ---

    // === TRAVELING: Smooth Arc Flight ===
    if (stateRef.current === 'TRAVELING' && targetObj) {
      const targetRadius = getSafeOrbitRadius(targetId!);

      // Calculate Vector to Planet Center
      const vecToPlanet = new Vector3().subVectors(targetPos, currentPos);
      const distToPlanet = vecToPlanet.length();

      // Flattened Direction (ignore Y diff for orbit plane entry)
      const flatDirToPlanet = new Vector3(vecToPlanet.x, 0, vecToPlanet.z).normalize();

      // Calculate "Tangential Entry Point"
      // Instead of flying to the front of the planet, we aim for the side (tangent)
      // Cross product with UP vector gives a tangent direction
      const tangentOffset = new Vector3(0, 1, 0).cross(flatDirToPlanet).normalize().multiplyScalar(targetRadius);

      // The Entry Point is on the orbit ring, offset by tangent
      // This makes the ship fly towards the "edge" of the planet, allowing seamless orbit entry
      const entryPoint = new Vector3(
          targetPos.x + tangentOffset.x,
          targetPos.y, // Align height
          targetPos.z + tangentOffset.z
      );

      const distToEntry = currentPos.distanceTo(entryPoint);

      // Speed Control
      let desiredSpeed = MAX_SPEED;
      if (distToEntry < 40) desiredSpeed = ORBIT_SPEED;
      currentSpeedRef.current += (desiredSpeed - currentSpeedRef.current) * 1.5 * delta;

      // Rotation / Steering Logic
      if (distToEntry < 2) {
         // --- TRANSITION TO ORBIT ---
         stateRef.current = 'ORBITING';
         orbitRadiusRef.current = targetRadius;

         // CRITICAL: Calculate exact angle from CURRENT position to avoid snap
         // atan2(z, x) relative to planet center
         const relativePos = new Vector3().subVectors(currentPos, targetPos);
         orbitAngleRef.current = Math.atan2(relativePos.z, relativePos.x);
         totalOrbitTraveledRef.current = 0;

      } else {
         // --- FLYING TOWARDS ENTRY ---

         // 1. Calculate Move Vector
         const moveDir = new Vector3().subVectors(entryPoint, currentPos).normalize();

         // 2. Position Update
         groupRef.current.position.add(moveDir.multiplyScalar(currentSpeedRef.current * delta));

         // 3. Rotation Update (The "Arc")
         // When far, turn slowly (wide arc). When close, align with orbit tangent.
         let lookTargetPos = currentPos.clone().add(moveDir);

         if (distToEntry < 20) {
             // NEAR ENTRY: Align with the Orbit Tangent (not just the point)
             // The expected orbit tangent at entry is roughly the moveDir
             // We blend towards looking strictly horizontal
             lookTargetPos.y = targetPos.y; 
         }

         const dummyObj = new Object3D();
         dummyObj.position.copy(currentPos);
         dummyObj.lookAt(lookTargetPos);

         // Slerp Factor: Lower = Wider Turns. 
         // Dynamic: Turn faster if we are getting closer but angle is off
         const turnRate = distToEntry < 30 ? 4.0 : 1.5; 
         groupRef.current.quaternion.slerp(dummyObj.quaternion, turnRate * delta);

         // Bank reset
         if (shipModelRef.current) {
            shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, 0, delta * 2);
         }
      }
    }

    // === ORBITING: Flat, Stable Circle ===
    if (stateRef.current === 'ORBITING' && targetObj) {
       currentSpeedRef.current += (ORBIT_SPEED - currentSpeedRef.current) * 2.0 * delta;

       // Orbital Physics
       const angularSpeed = currentSpeedRef.current / orbitRadiusRef.current;
       const angleDelta = angularSpeed * delta;

       orbitAngleRef.current += angleDelta;
       totalOrbitTraveledRef.current += angleDelta;

       // Position
       const nextX = targetPos.x + Math.cos(orbitAngleRef.current) * orbitRadiusRef.current;
       const nextZ = targetPos.z + Math.sin(orbitAngleRef.current) * orbitRadiusRef.current;
       const nextY = targetPos.y; // Flat orbit

       const nextPos = new Vector3(nextX, nextY, nextZ);
       groupRef.current.position.copy(nextPos);

       // Rotation: Look at Tangent
       // We look slightly ahead on the circle
       const futureAngle = orbitAngleRef.current + 0.2; 
       const lookX = targetPos.x + Math.cos(futureAngle) * orbitRadiusRef.current;
       const lookZ = targetPos.z + Math.sin(futureAngle) * orbitRadiusRef.current;

       const lookAtPos = new Vector3(lookX, nextY, lookZ);

       const dummyObj = new Object3D();
       dummyObj.position.copy(nextPos);
       dummyObj.lookAt(lookAtPos);

       // High slerp here to keep locked on tangent
       groupRef.current.quaternion.slerp(dummyObj.quaternion, 10 * delta);

       // Banking
       if (shipModelRef.current) {
           shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, -Math.PI / 4, delta * 3);
       }

       // Exit Condition
       if (totalOrbitTraveledRef.current > Math.PI * 2.2) {
          stateRef.current = 'LEAVING';

          // Capture current forward vector for tangential exit
          const forward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();
          exitVectorRef.current.copy(forward);
          leavingTimeRef.current = 0;
       }
    }

    // === LEAVING: Inertial Departure ===
    if (stateRef.current === 'LEAVING') {
       leavingTimeRef.current += delta;

       // Accelerate
       currentSpeedRef.current += (MAX_SPEED - currentSpeedRef.current) * 1.0 * delta;

       // Move straight along the exit tangent
       const moveVec = exitVectorRef.current.clone().multiplyScalar(currentSpeedRef.current * delta);
       groupRef.current.position.add(moveVec);

       // Un-bank
       if (shipModelRef.current) {
           shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, 0, delta * 2);
       }

       // Fly straight for longer (2.5s) to ensure we clear the planet and create a "departure" feel
       if (leavingTimeRef.current > 2.5) {
          stateRef.current = 'SEARCHING';
          setTargetId(null);
       }
    }

    // --- 3. HUD UPDATES ---
    const displayVal = Math.round(currentSpeedRef.current * 1000);
    if (Math.abs(displayVal - currentSpeedDisplay) > 100) {
        setCurrentSpeedDisplay(displayVal);
    }

    // --- 4. CAMERA SYSTEM ---
    const targetCamDist = stateRef.current === 'ORBITING' ? 35 : 18;
    camDistRef.current = MathUtils.lerp(camDistRef.current, targetCamDist, delta * 1.0);

    const shipForward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();

    // Height offset logic
    const heightOffset = MathUtils.lerp(5, 12, (camDistRef.current - 16) / (35 - 16));

    const camOffset = shipForward.clone().multiplyScalar(-camDistRef.current).add(new Vector3(0, heightOffset, 0));
    const desiredCamPos = groupRef.current.position.clone().add(camOffset);

    // Camera Smoothing
    state.camera.position.lerp(desiredCamPos, 0.08); 
    const lookTarget = groupRef.current.position.clone().add(shipForward.multiplyScalar(10));
    state.camera.lookAt(lookTarget);

  });

  return (
    <>
      <group ref={groupRef} scale={[1.8, 1.8, 1.8]}>
        <Html position={[2, 1, 0]} center transform sprite zIndexRange={[100, 0]}>
             <div className="flex flex-col items-start pointer-events-none select-none">
                <div className="bg-cyan-900/40 border-l-2 border-cyan-400 backdrop-blur-sm px-3 py-1 mb-1 transform skew-x-[-10deg]">
                   <span className="text-[10px] text-cyan-200 font-mono tracking-widest uppercase">Velocity</span>
                   <div className="text-xl font-bold text-white font-mono leading-none flex items-baseline gap-1">
                      {currentSpeedDisplay.toLocaleString()} 
                      <span className="text-[10px] text-cyan-400">KM/H</span>
                   </div>
                </div>
                <div className="flex gap-0.5 mt-0.5">
                   <div className={`h-1 w-2 rounded-sm ${currentSpeedRef.current > 5 ? 'bg-green-500' : 'bg-gray-700'}`}></div>
                   <div className={`h-1 w-2 rounded-sm ${currentSpeedRef.current > 10 ? 'bg-green-400' : 'bg-gray-700'}`}></div>
                   <div className={`h-1 w-2 rounded-sm ${currentSpeedRef.current > 15 ? 'bg-yellow-400' : 'bg-gray-700'}`}></div>
                   <div className={`h-1 w-2 rounded-sm ${currentSpeedRef.current > 20 ? 'bg-red-500' : 'bg-gray-700'}`}></div>
                </div>
             </div>
        </Html>

        <group ref={shipModelRef}>
            <group rotation={[Math.PI / 2, 0, 0]}>
                <mesh position={[0, 0, 0]}>
                  <cylinderGeometry args={[0.35, 0.35, 1.6, 32]} />
                  <meshPhysicalMaterial color="#e2e8f0" metalness={0.9} roughness={0.2} clearcoat={1.0} clearcoatRoughness={0.1} />
                </mesh>

                <group position={[0, 0, 0.36]} rotation={[0, 0, 0]}>
                     <Text color="black" fontSize={0.15} anchorX="center" anchorY="middle" rotation={[0, 0, -Math.PI/2]}>
                       小豆子号
                     </Text>
                     <mesh position={[0, 0, -0.01]} rotation={[0, 0, -Math.PI/2]}>
                        <planeGeometry args={[0.8, 0.25]} />
                        <meshBasicMaterial color="#fbbf24" transparent opacity={0.8} />
                     </mesh>
                </group>

                <mesh position={[0, 1.15, 0]}>
                  <coneGeometry args={[0.35, 0.7, 32]} />
                  <meshPhysicalMaterial color="#e2e8f0" metalness={0.9} roughness={0.2} clearcoat={1.0} />
                </mesh>

                <group position={[0, 1.0, 0]}>
                   <mesh position={[-0.32, 0, 0]} rotation={[0, 0, 0.2]}>
                      <boxGeometry args={[0.2, 0.3, 0.05]} />
                      <meshStandardMaterial color="#1a1a1a" roughness={0.4} />
                   </mesh>
                   <mesh position={[0.32, 0, 0]} rotation={[0, 0, -0.2]}>
                      <boxGeometry args={[0.2, 0.3, 0.05]} />
                      <meshStandardMaterial color="#1a1a1a" roughness={0.4} />
                   </mesh>
                </group>

                <group position={[0, -0.6, 0]}>
                   <mesh position={[-0.45, 0, 0]} rotation={[0, 0, 0.1]}>
                      <boxGeometry args={[0.3, 0.6, 0.08]} />
                      <meshStandardMaterial color="#1a1a1a" roughness={0.4} />
                   </mesh>
                   <mesh position={[0.45, 0, 0]} rotation={[0, 0, -0.1]}>
                      <boxGeometry args={[0.3, 0.6, 0.08]} />
                      <meshStandardMaterial color="#1a1a1a" roughness={0.4} />
                   </mesh>
                </group>

                <group position={[0, -0.85, 0]}>
                   <mesh position={[0, 0, 0]}>
                      <cylinderGeometry args={[0.25, 0.2, 0.1, 16]} />
                      <meshStandardMaterial color="#111" />
                   </mesh>
                   <mesh position={[0.1, -0.1, 0]}>
                       <cylinderGeometry args={[0.06, 0.08, 0.2, 8]} />
                       <meshStandardMaterial color="#222" />
                   </mesh>
                   <mesh position={[-0.1, -0.1, 0]}>
                       <cylinderGeometry args={[0.06, 0.08, 0.2, 8]} />
                       <meshStandardMaterial color="#222" />
                   </mesh>
                   <mesh position={[0, -0.1, 0.12]}>
                       <cylinderGeometry args={[0.06, 0.08, 0.2, 8]} />
                       <meshStandardMaterial color="#222" />
                   </mesh>
                </group>

                <mesh position={[0, -1.6, 0]}>
                  <cylinderGeometry args={[0.15, 0.0, 1.4, 16, 1, true]} /> 
                  <meshBasicMaterial color="#8B5CF6" transparent opacity={0.4} depthWrite={false} blending={AdditiveBlending} />
                </mesh>
                <mesh position={[0, -1.4, 0]}>
                  <cylinderGeometry args={[0.1, 0.0, 1.0, 16, 1, true]} /> 
                  <meshBasicMaterial color="#06b6d4" transparent opacity={0.6} depthWrite={false} blending={AdditiveBlending} />
                </mesh>
                 <mesh position={[0, -1.1, 0]}>
                  <cylinderGeometry args={[0.06, 0.0, 0.5, 8, 1, true]} /> 
                  <meshBasicMaterial color="#ffffff" transparent opacity={0.9} depthWrite={false} blending={AdditiveBlending} />
                </mesh>

                <pointLight position={[0, -1, 0]} color="#06b6d4" distance={5} intensity={4} />
            </group>
            <group position={[0, 0, -1.2]}>
              <Trail width={0.4} length={6} color="#06b6d4" attenuation={(t) => t * t}>
                <mesh visible={false}><boxGeometry args={[0.1, 0.1, 0.1]} /></mesh>
              </Trail>
            </group>
        </group>
      </group>

      {targetId && planetRefs.current[targetId] && stateRef.current === 'TRAVELING' && (
        <TargetIndicator targetObj={planetRefs.current[targetId]} />
      )}
    </>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { Vector3, Group, Object3D, AdditiveBlending, DoubleSide, Quaternion, MathUtils, Mesh } from 'three';
import { Trail, Html, Text } from '@react-three/drei';
import { PLANETS } from '../constants';

interface StarshipProps {
  planetRefs: React.MutableRefObject<{ [key: string]: Object3D }>;
}

type ShipState = 'SEARCHING' | 'TRAVELING' | 'ORBITING' | 'LEAVING';

// --- NEW SCI-FI ION INDICATOR ---
const TargetIndicator: React.FC<{ targetObj: Object3D }> = ({ targetObj }) => {
  const groupRef = useRef<Group>(null);
  const coreRef = useRef<Mesh>(null);
  const ring1Ref = useRef<Mesh>(null);
  const ring2Ref = useRef<Mesh>(null);

  useFrame((state, delta) => {
    if (groupRef.current && targetObj) {
      const worldPos = new Vector3();
      targetObj.getWorldPosition(worldPos);

      // Position marker significantly above the planet
      const hoverHeight = 16;
      // Smooth bobbing motion
      const bobbing = Math.sin(state.clock.elapsedTime * 2.5) * 0.5;

      const targetPos = worldPos.clone().add(new Vector3(0, hoverHeight + bobbing, 0));
      // Lerp for smooth tracking lag effect
      groupRef.current.position.lerp(targetPos, delta * 10);
    }

    // 1. Core Rotation & Breathing Pulse
    if (coreRef.current) {
        coreRef.current.rotation.y += delta;
        coreRef.current.rotation.z += delta * 0.5;
        const scale = 1 + Math.sin(state.clock.elapsedTime * 3) * 0.15;
        coreRef.current.scale.setScalar(scale);
    }

    // 2. Ring 1 (Horizontal Gyro)
    if (ring1Ref.current) {
        ring1Ref.current.rotation.z += delta * 2;
        ring1Ref.current.rotation.x = Math.sin(state.clock.elapsedTime * 0.5) * 0.2 + Math.PI/2; 
    }

    // 3. Ring 2 (Vertical Gyro)
    if (ring2Ref.current) {
        ring2Ref.current.rotation.y += delta * 1.5;
        ring2Ref.current.rotation.x += delta * 0.5;
    }
  });

  return (
    <group ref={groupRef}>
       {/* 1. Core Ion Crystal (Octahedron) */}
       <mesh ref={coreRef}>
          <octahedronGeometry args={[1.2, 0]} />
          <meshBasicMaterial 
            color="#00ffff" 
            wireframe 
            transparent 
            opacity={0.8} 
            blending={AdditiveBlending} 
          />
       </mesh>
       {/* Solid inner core for visibility */}
       <mesh scale={[0.6, 0.6, 0.6]}>
          <octahedronGeometry args={[1.2, 0]} />
          <meshBasicMaterial color="#ffffff" transparent opacity={0.9} blending={AdditiveBlending} />
       </mesh>

       {/* 2. Rotating Energy Rings */}
       {/* Ring 1 - Cyan */}
       <mesh ref={ring1Ref}>
          <torusGeometry args={[2.0, 0.05, 16, 64]} />
          <meshBasicMaterial color="#00ccff" transparent opacity={0.6} blending={AdditiveBlending} />
       </mesh>

       {/* Ring 2 - Greenish/Turquoise */}
       <mesh ref={ring2Ref} rotation={[0, 0, Math.PI/4]}>
          <torusGeometry args={[2.8, 0.03, 16, 64]} />
          <meshBasicMaterial color="#00ffaa" transparent opacity={0.4} blending={AdditiveBlending} />
       </mesh>

       {/* 3. Outer Glow Sphere (Holographic Field) */}
       <mesh>
          <sphereGeometry args={[4, 32, 32]} />
           <meshBasicMaterial 
            color="#00ffff" 
            transparent 
            opacity={0.08} 
            blending={AdditiveBlending} 
            depthWrite={false} 
            side={DoubleSide}
          />
       </mesh>

       {/* 4. Data Stream Beam (Projection to planet) */}
       <mesh position={[0, -8, 0]}>
          <cylinderGeometry args={[0.1, 0.0, 16, 8, 1, true]} />
          <meshBasicMaterial 
            color="#00ffff" 
            transparent 
            opacity={0.15} 
            blending={AdditiveBlending} 
            depthWrite={false} 
          />
       </mesh>

       {/* 5. Particle Bits (Floating data dust) */}
       <points position={[0,0,0]}>
           <sphereGeometry args={[3.5, 4, 4]} />
           <pointsMaterial color="#00ffff" size={0.15} transparent opacity={0.6} sizeAttenuation blending={AdditiveBlending} />
       </points>

       {/* 6. Light Source */}
       <pointLight color="#00ffff" intensity={3} distance={20} decay={2} />

       {/* 7. HUD Label */}
       <Html position={[0, 4.5, 0]} center sprite distanceFactor={15} zIndexRange={[100, 0]}>
          <div className="flex flex-col items-center pointer-events-none select-none">
             <div className="flex items-center gap-2 bg-black/60 border border-cyan-500/50 px-3 py-1.5 rounded-xl backdrop-blur-md shadow-[0_0_20px_rgba(0,255,255,0.4)] animate-pulse">
                <div className="w-2 h-2 rounded-full bg-cyan-400 shadow-[0_0_8px_#00ffff] animate-ping"></div>
                <span className="text-[10px] font-mono font-bold text-cyan-100 tracking-widest">LOCKED</span>
             </div>
             <div className="w-[1px] h-8 bg-gradient-to-b from-cyan-500 to-transparent opacity-50"></div>
          </div>
       </Html>
    </group>
  );
};

export const Starship: React.FC<StarshipProps> = ({ planetRefs }) => {
  const groupRef = useRef<Group>(null);
  const shipModelRef = useRef<Group>(null);

  // Logic State
  const [targetId, setTargetId] = useState<string | null>(null);
  const [currentSpeedDisplay, setCurrentSpeedDisplay] = useState(0);

  const stateRef = useRef<ShipState>('SEARCHING');
  const initializedRef = useRef(false);

  // Movement calculation refs
  const currentSpeedRef = useRef(0);
  const orbitAngleRef = useRef(0);
  const orbitRadiusRef = useRef(15);
  const totalOrbitTraveledRef = useRef(0);
  const camDistRef = useRef(16); 

  // Leaving/Vector Refs
  const exitVectorRef = useRef(new Vector3());
  const leavingTimeRef = useRef(0);
  const flightVectorRef = useRef(new Vector3(0, 0, 1)); // Direction of flight

  // Constants
  const MAX_SPEED = 25; 
  const ORBIT_SPEED = 8; 

  const getSafeOrbitRadius = (id: string) => {
     const p = PLANETS.find(x => x.id === id);
     if (!p) return 12;
     return p.hasRings ? p.size * 2.5 + 2.0 : p.size * 1.8 + 2.0; 
  };

  useFrame((state, delta) => {
    if (!groupRef.current) return;

    // --- 0. INITIALIZATION ---
    if (!initializedRef.current) {
      const earthObj = planetRefs.current['earth'];
      if (earthObj) {
        const startPos = new Vector3();
        earthObj.getWorldPosition(startPos);
        if (startPos.lengthSq() > 1) {
             startPos.y += 10.0;
             startPos.x += 10.0; 
             groupRef.current.position.copy(startPos);
             groupRef.current.lookAt(new Vector3(0, 0, 0)); 
             initializedRef.current = true;

             // Initial Flight Vector
             groupRef.current.getWorldDirection(flightVectorRef.current);

             const initCamPos = startPos.clone().add(new Vector3(0, 10, 25));
             state.camera.position.copy(initCamPos);
             state.camera.lookAt(startPos);
        }
      }
      return; 
    }

    // --- 1. TARGET MANAGEMENT ---
    if (stateRef.current === 'SEARCHING') {
      const ids = Object.keys(planetRefs.current);
      if (ids.length > 0) {
        const currentPos = groupRef.current.position;
        // Don't pick nearby planets
        const validIds = ids.filter(id => {
           const pObj = planetRefs.current[id];
           const pPos = new Vector3();
           pObj.getWorldPosition(pPos);
           return pPos.distanceTo(currentPos) > 60; 
        });

        const nextId = validIds.length > 0 
           ? validIds[Math.floor(Math.random() * validIds.length)]
           : ids[Math.floor(Math.random() * ids.length)];

        setTargetId(nextId);
        stateRef.current = 'TRAVELING';
      }
      return;
    }

    let targetObj: Object3D | null = null;
    let targetPos = new Vector3();
    if (targetId && planetRefs.current[targetId]) {
      targetObj = planetRefs.current[targetId];
      targetObj.getWorldPosition(targetPos);
    }

    const currentPos = groupRef.current.position.clone();

    // --- 2. STATE LOGIC ---

    // === TRAVELING: Smooth Arc Flight ===
    if (stateRef.current === 'TRAVELING' && targetObj) {
      const targetRadius = getSafeOrbitRadius(targetId!);

      // Calculate Vector to Planet Center
      const vecToPlanet = new Vector3().subVectors(targetPos, currentPos);
      const distToPlanet = vecToPlanet.length();

      // Flattened Direction (ignore Y diff for orbit plane entry)
      const flatDirToPlanet = new Vector3(vecToPlanet.x, 0, vecToPlanet.z).normalize();

      // Calculate "Tangential Entry Point"
      // Instead of flying to the front of the planet, we aim for the side (tangent)
      // Cross product with UP vector gives a tangent direction
      const tangentOffset = new Vector3(0, 1, 0).cross(flatDirToPlanet).normalize().multiplyScalar(targetRadius);

      // The Entry Point is on the orbit ring, offset by tangent
      // This makes the ship fly towards the "edge" of the planet, allowing seamless orbit entry
      const entryPoint = new Vector3(
          targetPos.x + tangentOffset.x,
          targetPos.y, // Align height
          targetPos.z + tangentOffset.z
      );

      const distToEntry = currentPos.distanceTo(entryPoint);

      // Speed Control
      let desiredSpeed = MAX_SPEED;
      if (distToEntry < 40) desiredSpeed = ORBIT_SPEED;
      currentSpeedRef.current += (desiredSpeed - currentSpeedRef.current) * 1.5 * delta;

      // Rotation / Steering Logic
      if (distToEntry < 2) {
         // --- TRANSITION TO ORBIT ---
         stateRef.current = 'ORBITING';
         orbitRadiusRef.current = targetRadius;

         // CRITICAL: Calculate exact angle from CURRENT position to avoid snap
         // atan2(z, x) relative to planet center
         const relativePos = new Vector3().subVectors(currentPos, targetPos);
         orbitAngleRef.current = Math.atan2(relativePos.z, relativePos.x);
         totalOrbitTraveledRef.current = 0;

      } else {
         // --- FLYING TOWARDS ENTRY ---

         // 1. Calculate Move Vector
         const moveDir = new Vector3().subVectors(entryPoint, currentPos).normalize();

         // 2. Position Update
         groupRef.current.position.add(moveDir.multiplyScalar(currentSpeedRef.current * delta));

         // 3. Rotation Update (The "Arc")
         // When far, turn slowly (wide arc). When close, align with orbit tangent.
         let lookTargetPos = currentPos.clone().add(moveDir);

         if (distToEntry < 20) {
             // NEAR ENTRY: Align with the Orbit Tangent (not just the point)
             // The expected orbit tangent at entry is roughly the moveDir
             // We blend towards looking strictly horizontal
             lookTargetPos.y = targetPos.y; 
         }

         const dummyObj = new Object3D();
         dummyObj.position.copy(currentPos);
         dummyObj.lookAt(lookTargetPos);

         // Slerp Factor: Lower = Wider Turns. 
         // Dynamic: Turn faster if we are getting closer but angle is off
         const turnRate = distToEntry < 30 ? 4.0 : 1.5; 
         groupRef.current.quaternion.slerp(dummyObj.quaternion, turnRate * delta);

         // Bank reset
         if (shipModelRef.current) {
            shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, 0, delta * 2);
         }
      }
    }

    // === ORBITING: Flat, Stable Circle ===
    if (stateRef.current === 'ORBITING' && targetObj) {
       currentSpeedRef.current += (ORBIT_SPEED - currentSpeedRef.current) * 2.0 * delta;

       // Orbital Physics
       const angularSpeed = currentSpeedRef.current / orbitRadiusRef.current;
       const angleDelta = angularSpeed * delta;

       orbitAngleRef.current += angleDelta;
       totalOrbitTraveledRef.current += angleDelta;

       // Position
       const nextX = targetPos.x + Math.cos(orbitAngleRef.current) * orbitRadiusRef.current;
       const nextZ = targetPos.z + Math.sin(orbitAngleRef.current) * orbitRadiusRef.current;
       const nextY = targetPos.y; // Flat orbit

       const nextPos = new Vector3(nextX, nextY, nextZ);
       groupRef.current.position.copy(nextPos);

       // Rotation: Look at Tangent
       // We look slightly ahead on the circle
       const futureAngle = orbitAngleRef.current + 0.2; 
       const lookX = targetPos.x + Math.cos(futureAngle) * orbitRadiusRef.current;
       const lookZ = targetPos.z + Math.sin(futureAngle) * orbitRadiusRef.current;

       const lookAtPos = new Vector3(lookX, nextY, lookZ);

       const dummyObj = new Object3D();
       dummyObj.position.copy(nextPos);
       dummyObj.lookAt(lookAtPos);

       // High slerp here to keep locked on tangent
       groupRef.current.quaternion.slerp(dummyObj.quaternion, 10 * delta);

       // Banking
       if (shipModelRef.current) {
           shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, -Math.PI / 4, delta * 3);
       }

       // Exit Condition
       if (totalOrbitTraveledRef.current > Math.PI * 2.2) {
          stateRef.current = 'LEAVING';

          // Capture current forward vector for tangential exit
          const forward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();
          exitVectorRef.current.copy(forward);
          leavingTimeRef.current = 0;
       }
    }

    // === LEAVING: Inertial Departure ===
    if (stateRef.current === 'LEAVING') {
       leavingTimeRef.current += delta;

       // Accelerate
       currentSpeedRef.current += (MAX_SPEED - currentSpeedRef.current) * 1.0 * delta;

       // Move straight along the exit tangent
       const moveVec = exitVectorRef.current.clone().multiplyScalar(currentSpeedRef.current * delta);
       groupRef.current.position.add(moveVec);

       // Un-bank
       if (shipModelRef.current) {
           shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, 0, delta * 2);
       }

       // Fly straight for longer (2.5s) to ensure we clear the planet and create a "departure" feel
       if (leavingTimeRef.current > 2.5) {
          stateRef.current = 'SEARCHING';
          setTargetId(null);
       }
    }

    // --- 3. HUD UPDATES ---
    const displayVal = Math.round(currentSpeedRef.current * 1000);
    if (Math.abs(displayVal - currentSpeedDisplay) > 100) {
        setCurrentSpeedDisplay(displayVal);
    }

    // --- 4. CAMERA SYSTEM ---
    const targetCamDist = stateRef.current === 'ORBITING' ? 35 : 18;
    camDistRef.current = MathUtils.lerp(camDistRef.current, targetCamDist, delta * 1.0);

    const shipForward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();

    // Height offset logic
    const heightOffset = MathUtils.lerp(5, 12, (camDistRef.current - 16) / (35 - 16));

    const camOffset = shipForward.clone().multiplyScalar(-camDistRef.current).add(new Vector3(0, heightOffset, 0));
    const desiredCamPos = groupRef.current.position.clone().add(camOffset);

    // Camera Smoothing
    state.camera.position.lerp(desiredCamPos, 0.08); 
    const lookTarget = groupRef.current.position.clone().add(shipForward.multiplyScalar(10));
    state.camera.lookAt(lookTarget);

  });

  return (
    <>
      <group ref={groupRef} scale={[1.8, 1.8, 1.8]}>
        <Html position={[2, 1, 0]} center transform sprite zIndexRange={[100, 0]}>
             <div className="flex flex-col items-start pointer-events-none select-none">
                <div className="bg-cyan-900/40 border-l-2 border-cyan-400 backdrop-blur-sm px-3 py-1 mb-1 transform skew-x-[-10deg]">
                   <span className="text-[10px] text-cyan-200 font-mono tracking-widest uppercase">Velocity</span>
                   <div className="text-xl font-bold text-white font-mono leading-none flex items-baseline gap-1">
                      {currentSpeedDisplay.toLocaleString()} 
                      <span className="text-[10px] text-cyan-400">KM/H</span>
                   </div>
                </div>
                <div className="flex gap-0.5 mt-0.5">
                   <div className={`h-1 w-2 rounded-sm ${currentSpeedRef.current > 5 ? 'bg-green-500' : 'bg-gray-700'}`}></div>
                   <div className={`h-1 w-2 rounded-sm ${currentSpeedRef.current > 10 ? 'bg-green-400' : 'bg-gray-700'}`}></div>
                   <div className={`h-1 w-2 rounded-sm ${currentSpeedRef.current > 15 ? 'bg-yellow-400' : 'bg-gray-700'}`}></div>
                   <div className={`h-1 w-2 rounded-sm ${currentSpeedRef.current > 20 ? 'bg-red-500' : 'bg-gray-700'}`}></div>
                </div>
             </div>
        </Html>

        <group ref={shipModelRef}>
            <group rotation={[Math.PI / 2, 0, 0]}>
                <mesh position={[0, 0, 0]}>
                  <cylinderGeometry args={[0.35, 0.35, 1.6, 32]} />
                  <meshPhysicalMaterial color="#e2e8f0" metalness={0.9} roughness={0.2} clearcoat={1.0} clearcoatRoughness={0.1} />
                </mesh>

                <group position={[0, 0, 0.36]} rotation={[0, 0, 0]}>
                     <Text color="black" fontSize={0.15} anchorX="center" anchorY="middle" rotation={[0, 0, -Math.PI/2]}>
                       小豆子号
                     </Text>
                     <mesh position={[0, 0, -0.01]} rotation={[0, 0, -Math.PI/2]}>
                        <planeGeometry args={[0.8, 0.25]} />
                        <meshBasicMaterial color="#fbbf24" transparent opacity={0.8} />
                     </mesh>
                </group>

                <mesh position={[0, 1.15, 0]}>
                  <coneGeometry args={[0.35, 0.7, 32]} />
                  <meshPhysicalMaterial color="#e2e8f0" metalness={0.9} roughness={0.2} clearcoat={1.0} />
                </mesh>

                <group position={[0, 1.0, 0]}>
                   <mesh position={[-0.32, 0, 0]} rotation={[0, 0, 0.2]}>
                      <boxGeometry args={[0.2, 0.3, 0.05]} />
                      <meshStandardMaterial color="#1a1a1a" roughness={0.4} />
                   </mesh>
                   <mesh position={[0.32, 0, 0]} rotation={[0, 0, -0.2]}>
                      <boxGeometry args={[0.2, 0.3, 0.05]} />
                      <meshStandardMaterial color="#1a1a1a" roughness={0.4} />
                   </mesh>
                </group>

                <group position={[0, -0.6, 0]}>
                   <mesh position={[-0.45, 0, 0]} rotation={[0, 0, 0.1]}>
                      <boxGeometry args={[0.3, 0.6, 0.08]} />
                      <meshStandardMaterial color="#1a1a1a" roughness={0.4} />
                   </mesh>
                   <mesh position={[0.45, 0, 0]} rotation={[0, 0, -0.1]}>
                      <boxGeometry args={[0.3, 0.6, 0.08]} />
                      <meshStandardMaterial color="#1a1a1a" roughness={0.4} />
                   </mesh>
                </group>

                <group position={[0, -0.85, 0]}>
                   <mesh position={[0, 0, 0]}>
                      <cylinderGeometry args={[0.25, 0.2, 0.1, 16]} />
                      <meshStandardMaterial color="#111" />
                   </mesh>
                   <mesh position={[0.1, -0.1, 0]}>
                       <cylinderGeometry args={[0.06, 0.08, 0.2, 8]} />
                       <meshStandardMaterial color="#222" />
                   </mesh>
                   <mesh position={[-0.1, -0.1, 0]}>
                       <cylinderGeometry args={[0.06, 0.08, 0.2, 8]} />
                       <meshStandardMaterial color="#222" />
                   </mesh>
                   <mesh position={[0, -0.1, 0.12]}>
                       <cylinderGeometry args={[0.06, 0.08, 0.2, 8]} />
                       <meshStandardMaterial color="#222" />
                   </mesh>
                </group>

                <mesh position={[0, -1.6, 0]}>
                  <cylinderGeometry args={[0.15, 0.0, 1.4, 16, 1, true]} /> 
                  <meshBasicMaterial color="#8B5CF6" transparent opacity={0.4} depthWrite={false} blending={AdditiveBlending} />
                </mesh>
                <mesh position={[0, -1.4, 0]}>
                  <cylinderGeometry args={[0.1, 0.0, 1.0, 16, 1, true]} /> 
                  <meshBasicMaterial color="#06b6d4" transparent opacity={0.6} depthWrite={false} blending={AdditiveBlending} />
                </mesh>
                 <mesh position={[0, -1.1, 0]}>
                  <cylinderGeometry args={[0.06, 0.0, 0.5, 8, 1, true]} /> 
                  <meshBasicMaterial color="#ffffff" transparent opacity={0.9} depthWrite={false} blending={AdditiveBlending} />
                </mesh>

                <pointLight position={[0, -1, 0]} color="#06b6d4" distance={5} intensity={4} />
            </group>
            <group position={[0, 0, -1.2]}>
              <Trail width={0.4} length={6} color="#06b6d4" attenuation={(t) => t * t}>
                <mesh visible={false}><boxGeometry args={[0.1, 0.1, 0.1]} /></mesh>
              </Trail>
            </group>
        </group>
      </group>

      {targetId && planetRefs.current[targetId] && stateRef.current === 'TRAVELING' && (
        <TargetIndicator targetObj={planetRefs.current[targetId]} />
      )}
    </>
  );
};
